import{c as n,S as a,j as t,m as i}from"./chunks/framework.8aa1YH_s.js";const m=JSON.parse('{"title":"Tìm & Mua khóa học","description":"","frontmatter":{},"headers":[],"relativePath":"hoc-vien/mua-khoa-hoc.md","filePath":"hoc-vien/mua-khoa-hoc.md","lastUpdated":0}'),o={name:"hoc-vien/mua-khoa-hoc.md"};function c(r,h,e,l,g,u){return a(),t("div",null,[...h[0]||(h[0]=[i('<h1 id="tim-mua-khoa-hoc" tabindex="-1">Tìm &amp; Mua khóa học <a class="header-anchor" href="#tim-mua-khoa-hoc" aria-label="Permalink to “Tìm &amp; Mua khóa học”">​</a></h1><h2 id="kham-pha-khoa-hoc" tabindex="-1">Khám phá khóa học <a class="header-anchor" href="#kham-pha-khoa-hoc" aria-label="Permalink to “Khám phá khóa học”">​</a></h2><h3 id="tu-trang-chu" tabindex="-1">Từ trang chủ <a class="header-anchor" href="#tu-trang-chu" aria-label="Permalink to “Từ trang chủ”">​</a></h3><p>Truy cập <code>https://lamsonedutech.vn/home</code> hoặc <code>https://lamsonedutech.vn/luyen-tap/trang-chu</code>. Bạn sẽ thấy:</p><ul><li><strong>Banner khuyến mãi</strong> ở slider chính.</li><li><strong>Khóa học nổi bật</strong> theo từng nhóm: <ul><li>Luyện thi ĐGNL (HSA)</li><li>Luyện thi ĐGTD (TSA)</li><li>Tốt nghiệp THPT</li><li>Kiểm tra đầu vào</li><li>Học liệu, giáo trình</li></ul></li><li><strong>Khóa mới</strong> và <strong>Bán chạy</strong>.</li></ul><h3 id="theo-khung-chuong-trinh" tabindex="-1">Theo khung chương trình <a class="header-anchor" href="#theo-khung-chuong-trinh" aria-label="Permalink to “Theo khung chương trình”">​</a></h3><ul><li>Trên menu: chọn <strong>Khung chương trình</strong> (vd: &quot;ĐGNL 2026&quot;).</li><li>Trang khung hiển thị các khóa con của khung đó.</li><li>Đường dẫn: <code>https://lamsonedutech.vn/luyen-tap/chuong-trinh/:idKCT</code>.</li></ul><h3 id="theo-loai-chuong-trinh" tabindex="-1">Theo loại chương trình <a class="header-anchor" href="#theo-loai-chuong-trinh" aria-label="Permalink to “Theo loại chương trình”">​</a></h3><ul><li>Bấm vào menu <strong>Theo loại</strong> (hoặc đường dẫn <code>https://lamsonedutech.vn/luyen-tap/loai-chuong-trinh/:idTypeKCT</code>).</li><li>Lọc nhanh: Thi thử ĐGNL, Thi thử ĐGTD, TN THPT, Học liệu...</li></ul><h3 id="tim-kiem" tabindex="-1">Tìm kiếm <a class="header-anchor" href="#tim-kiem" aria-label="Permalink to “Tìm kiếm”">​</a></h3><ul><li>Sử dụng thanh tìm kiếm trên đầu trang.</li><li>Gõ từ khóa: &quot;HSA Toán&quot;, &quot;Văn 12&quot;, &quot;luyện thi&quot;...</li></ul><h2 id="trang-chi-tiet-khoa" tabindex="-1">Trang chi tiết khóa <a class="header-anchor" href="#trang-chi-tiet-khoa" aria-label="Permalink to “Trang chi tiết khóa”">​</a></h2><p><code>https://lamsonedutech.vn/luyen-tap/gioi-thieu-khoa-hoc/:idCourse</code></p><p>Trang này có:</p><ul><li><strong>Ảnh bìa, tên khóa</strong>.</li><li><strong>Giáo viên phụ trách</strong> (ảnh + bio).</li><li><strong>Giá gốc, giá khuyến mãi</strong>.</li><li><strong>Nút Mua khóa / Thêm vào giỏ</strong>.</li><li><strong>Mô tả chi tiết</strong>: bạn sẽ học gì, đầu ra cam kết, lộ trình.</li><li><strong>Cấu trúc nội dung</strong>: chương → chuyên đề (xem trước số bài giảng, đề thi).</li><li><strong>Học thử miễn phí</strong>: một vài bài giảng đầu để bạn xem trước (nếu giáo viên cấu hình).</li><li><strong>Nhận xét của học viên cũ</strong>.</li></ul><h2 id="so-sanh-khoa-hoc" tabindex="-1">So sánh khóa học <a class="header-anchor" href="#so-sanh-khoa-hoc" aria-label="Permalink to “So sánh khóa học”">​</a></h2><p>Để chọn khóa phù hợp, đối chiếu:</p><table tabindex="0"><thead><tr><th>Yếu tố</th><th>Cần xem</th></tr></thead><tbody><tr><td>Mục tiêu</td><td>Khóa có đúng kỳ thi bạn nhắm tới? (HSA / TSA / THPT)</td></tr><tr><td>Trình độ</td><td>Khóa &quot;Nền tảng&quot; / &quot;Chuyên đề&quot; / &quot;Thực chiến&quot;?</td></tr><tr><td>Giáo viên</td><td>Có giảng viên uy tín không?</td></tr><tr><td>Cấu trúc</td><td>Số chuyên đề, số đề thi đủ chưa?</td></tr><tr><td>Học thử</td><td>Có cho học thử không? Có chất lượng không?</td></tr><tr><td>Giá &amp; Thời hạn</td><td>Giá phù hợp ngân sách? Dùng được bao lâu?</td></tr><tr><td>Đánh giá</td><td>Học viên cũ nói gì?</td></tr></tbody></table><h2 id="mua-khoa" tabindex="-1">Mua khóa <a class="header-anchor" href="#mua-khoa" aria-label="Permalink to “Mua khóa”">​</a></h2><h3 id="cach-1-mua-nhanh-mua-ngay" tabindex="-1">Cách 1: Mua nhanh (Mua ngay) <a class="header-anchor" href="#cach-1-mua-nhanh-mua-ngay" aria-label="Permalink to “Cách 1: Mua nhanh (Mua ngay)”">​</a></h3><ol><li>Bấm <strong>Mua ngay</strong> trên trang khóa.</li><li>Hệ thống chuyển thẳng tới trang Thanh toán.</li><li>→ Xem <a href="./gio-hang-thanh-toan">Giỏ hàng &amp; Thanh toán</a>.</li></ol><h3 id="cach-2-them-vao-gio-roi-mua-sau" tabindex="-1">Cách 2: Thêm vào giỏ rồi mua sau <a class="header-anchor" href="#cach-2-them-vao-gio-roi-mua-sau" aria-label="Permalink to “Cách 2: Thêm vào giỏ rồi mua sau”">​</a></h3><ol><li>Bấm <strong>Thêm vào giỏ</strong>.</li><li>Tiếp tục xem các khóa khác.</li><li>Khi muốn thanh toán, bấm icon <strong>Giỏ hàng</strong> ở góc trên phải.</li><li>Vào trang <code>https://lamsonedutech.vn/luyen-tap/gio-hang/:id</code>.</li><li>Bấm <strong>Thanh toán</strong>.</li></ol><h3 id="cach-3-khoa-mien-phi" tabindex="-1">Cách 3: Khóa miễn phí <a class="header-anchor" href="#cach-3-khoa-mien-phi" aria-label="Permalink to “Cách 3: Khóa miễn phí”">​</a></h3><ul><li>Khóa có giá 0đ chỉ cần bấm <strong>Đăng ký miễn phí</strong> → bạn vào học ngay không cần thanh toán.</li></ul><h2 id="hoc-thu-truoc-khi-mua" tabindex="-1">Học thử trước khi mua <a class="header-anchor" href="#hoc-thu-truoc-khi-mua" aria-label="Permalink to “Học thử trước khi mua”">​</a></h2><p>Tại trang chi tiết khóa:</p><ul><li>Bấm vào bài giảng có icon <strong>🎁 Học thử</strong> để xem miễn phí (thường 5-15 phút).</li><li>Xem giáo viên giảng có dễ hiểu không, có hợp phong cách của bạn không.</li><li>Đọc nhận xét học viên cũ.</li></ul><blockquote><p>💡 <strong>Lời khuyên:</strong> đừng mua khóa mà chưa học thử ít nhất 1 bài giảng.</p></blockquote><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Mua khóa rồi có học vĩnh viễn không?</strong> → Tùy khóa - mỗi khóa có <strong>thời hạn sử dụng</strong> ghi rõ (vd: 6 tháng / 1 năm / Vĩnh viễn). Đọc kỹ trước khi mua.</p><p><strong>Có chính sách hoàn tiền không?</strong> → Liên hệ trung tâm. Thường có chính sách hoàn tiền trong 7 ngày đầu nếu chưa học quá X% nội dung.</p><p><strong>Tôi mua nhầm khóa thì sao?</strong> → Liên hệ hotline / Hỏi đáp ngay - trung tâm có thể đổi khóa nếu chưa học.</p><p><strong>Khóa có tích hợp livestream không?</strong> → Một số khóa có. Xem trong <strong>mô tả khóa</strong> hoặc liên hệ giáo viên qua Hỏi đáp.</p>',34)])])}const d=n(o,[["render",c]]);export{m as __pageData,d as default};
